\displaystyle{\begin{aligned}
   {\frac{\frac{4}{r}}{24+\frac{4y}{3}}} 
      \amp = {\frac{\frac{4}{r}}{24+\frac{4y}{3}}} \cdot \frac{{3r}}{{3r}} \\
      \amp = \frac{ \frac{4}{r} \cdot 3 r}{(24+\frac{4 y}{3}) \cdot 3 r} \\
      \amp = \frac{4 \cdot 3}{24 \cdot 3 r + \frac{4 y}{3} \cdot 3 r} \\
      \amp = \frac{12}{72 r + 4 r y} \\
      \amp = \frac{12}{4 r (18 + y)} \\
      \amp = {\frac{3}{r\mathopen{}\left(y+18\right)}\hbox{ or }\frac{3}{ry+18r}}
\end{aligned}
    }
